class OptimaSPAMain{constructor(){this.contentContainer=document.querySelector('#content-area,.content-wrapper,main');this.currentPath=window.location.pathname;this.isLoading=false;this.enableSPA=true;if(!this.contentContainer){console.warn('❌ SPA:Content container not found. Using full reload mode.')}console.log('🚀 OPTIMA SPA Main System Initialized(Enhanced Reload Mode)');this.init()}init(){this.setupMenuClickListener();this.setupPopStateListener();this.setupActiveStates();this.preserveScrollPosition();this.restoreSidebarState()}setupMenuClickListener(){document.body.addEventListener('click',(e)=>{const link=e.target.closest('a[href]');if(link&&this.isMenuLink(link)){e.preventDefault();this.saveScrollPosition();this.navigateWithReload(link.href)}})};isMenuLink(link){const href=link.getAttribute('href');if(!href||link.hostname !==location.hostname||link.target||href.startsWith('#')||href.startsWith('mailto:')||href.startsWith('tel:')||link.classList.contains('no-spa')||/\.(pdf|zip|jpg|png)$/i.test(href)){return false}const isMenuLink=link.closest('.sidebar,.nav,.navbar,.menu')||link.classList.contains('nav-link')||link.classList.contains('menu-link');return isMenuLink}setupPopStateListener(){window.addEventListener('popstate',()=>{console.log('SPA:Browser navigation detected,reloading for data consistency');this.saveScrollPosition();window.location.reload()})}setupActiveStates(){this.updateActiveStates();window.addEventListener('load',()=>{this.updateActiveStates();this.restoreScrollPosition()})}updateActiveStates(){const currentPath=window.location.pathname;document.querySelectorAll('.nav-link.active').forEach(link=>{link.classList.remove('active')});const activeLink=this.findActiveLink(currentPath);if(activeLink){activeLink.classList.add('active');this.expandParentDropdown(activeLink);console.log('✅ Active state set for:',activeLink.textContent.trim())}}findActiveLink(currentPath){let activeLink=document.querySelector(`a.nav-link[href="${currentPath}"]`);if(activeLink)return activeLink;const fullUrl=window.location.origin+currentPath;activeLink=document.querySelector(`a.nav-link[href="${fullUrl}"]`);if(activeLink)return activeLink;const navLinks=document.querySelectorAll('a.nav-link[href]');for(const link of navLinks){try{const linkUrl=new URL(link.href);if(linkUrl.pathname===currentPath){return link}}catch(e){continue}}let bestMatch=null;let bestMatchLength=0;for(const link of navLinks){try{const linkUrl=new URL(link.href);const linkPath=linkUrl.pathname;if(currentPath.startsWith(linkPath)&&linkPath.length>bestMatchLength){bestMatch=link;bestMatchLength=linkPath.length}}catch(e){continue}}return bestMatch}expandParentDropdown(activeLink){const parentCollapse=activeLink.closest('.collapse');if(parentCollapse){parentCollapse.classList.add('show');const toggleButton=document.querySelector(`[data-bs-target="#${parentCollapse.id}"],[href="#${parentCollapse.id}"]`);if(toggleButton){toggleButton.setAttribute('aria-expanded','true');toggleButton.classList.remove('collapsed')}}const parentDropdown=activeLink.closest('.dropdown-menu');if(parentDropdown){parentDropdown.classList.add('show');const toggleButton=parentDropdown.previousElementSibling;if(toggleButton){toggleButton.classList.add('show')}}}saveScrollPosition(){const sidebar=document.querySelector('.sidebar-nav,.sidebar,#sidebar');if(sidebar){const scrollPos=sidebar.scrollTop;sessionStorage.setItem('sidebar-scroll-position',scrollPos);console.log('💾 Saved sidebar scroll position:',scrollPos)}}restoreScrollPosition(){const sidebar=document.querySelector('.sidebar-nav,.sidebar,#sidebar');if(sidebar){const savedPos=sessionStorage.getItem('sidebar-scroll-position');if(savedPos !==null){const scrollPos=parseInt(savedPos);requestAnimationFrame(()=>{sidebar.scrollTop=scrollPos;console.log('📜 Restored sidebar scroll position:',scrollPos)})}}}preserveScrollPosition(){window.addEventListener('beforeunload',()=>{this.saveScrollPosition()})}restoreSidebarState(){const isCollapsed=localStorage.getItem('optima-sidebar-collapsed')==='true';const sidebar=document.querySelector('.sidebar');const mainContent=document.querySelector('.main-content');if(sidebar&&mainContent&&isCollapsed){sidebar.classList.add('collapsed');mainContent.classList.add('expanded');setTimeout(()=>{if(typeof window.updateSidebarTooltips==='function'){window.updateSidebarTooltips(true)}},100)}}scrollToActiveItem(){const activeLink=document.querySelector('.nav-link.active');const sidebar=document.querySelector('.sidebar-nav,.sidebar,#sidebar');if(activeLink&&sidebar){const linkRect=activeLink.getBoundingClientRect();const sidebarRect=sidebar.getBoundingClientRect();if(linkRect.top<sidebarRect.top||linkRect.bottom>sidebarRect.bottom){activeLink.scrollIntoView({behavior:'smooth',block:'center'});console.log('📍 Scrolled to active menu item')}}}navigateWithReload(url){if(this.isLoading){return}this.isLoading=true;this.showLoadingIndicator();console.log(`SPA:Navigating to ${url}with reload mode`);setTimeout(()=>{window.location.href=url},200)}showLoadingIndicator(){let indicator=document.getElementById('spa-loading-indicator');if(!indicator){indicator=document.createElement('div');indicator.id='spa-loading-indicator';indicator.style.cssText=` position:fixed;top:0;left:0;width:100%;height:4px;background:linear-gradient(90deg,#0d6efd 0%,#20c997 50%,#0d6efd 100%);background-size:200% 100%;animation:loading-wave 1s ease-in-out infinite;z-index:9999;`;if(!document.getElementById('spa-loading-style')){const style=document.createElement('style');style.id='spa-loading-style';style.textContent=` @keyframes loading-wave{0%{background-position:200% 0}100%{background-position:-200% 0}}.nav-link.active{background:linear-gradient(135deg,rgba(0,97,242,0.1)0%,rgba(77,140,255,0.1)100%)!important;border-left:3px solid #0061f2 !important;color:#0061f2 !important;font-weight:600 !important;position:relative}.nav-link.active::after{content:'';position:absolute;right:1rem;top:50%;transform:translateY(-50%);width:8px;height:8px;background:#0061f2;border-radius:50%;opacity:0.8}.nav-link.active .nav-link-text{color:#0061f2 !important}.nav-link.active i{color:#0061f2 !important}`;document.head.appendChild(style)}document.body.appendChild(indicator)}indicator.style.display='block'}hideLoadingIndicator(){this.isLoading=false;const indicator=document.getElementById('spa-loading-indicator');if(indicator){indicator.remove()}}}if(typeof window.optimaSPA==='undefined'){window.optimaSPA=new OptimaSPAMain()}else{console.log('📋 OptimaSPAMain already running.')}window.toggleSidebar=function(){const sidebar=document.querySelector('.sidebar');const mainContent=document.querySelector('.main-content');if(!sidebar||!mainContent){console.warn('Sidebar or main content not found');return}sidebar.classList.toggle('collapsed');mainContent.classList.toggle('expanded');const isCollapsed=sidebar.classList.contains('collapsed');localStorage.setItem('optima-sidebar-collapsed',isCollapsed);updateSidebarTooltips(isCollapsed);setTimeout(()=>{window.dispatchEvent(new Event('resize'))},300);console.log(`Sidebar ${isCollapsed ? 'collapsed':'expanded'}`)};window.updateSidebarTooltips=function(isCollapsed){const sidebar=document.querySelector('.sidebar');if(!sidebar)return;const navLinks=sidebar.querySelectorAll('.nav-link');navLinks.forEach(link=>{const textElement=link.querySelector('.nav-link-text');if(textElement){const text=textElement.textContent.trim();if(isCollapsed){if(!link.hasAttribute('data-bs-toggle')){link.setAttribute('data-bs-toggle','tooltip');link.setAttribute('data-bs-placement','right');link.setAttribute('title',text)}}else{link.removeAttribute('data-bs-toggle');link.removeAttribute('data-bs-placement');link.removeAttribute('title')}}});if(typeof bootstrap !=='undefined'&&bootstrap.Tooltip){const existingTooltips=sidebar.querySelectorAll('[data-bs-toggle="tooltip"]');existingTooltips.forEach(el=>{const tooltip=bootstrap.Tooltip.getInstance(el);if(tooltip)tooltip.dispose()});if(isCollapsed){const tooltipTriggerList=sidebar.querySelectorAll('[data-bs-toggle="tooltip"]');tooltipTriggerList.forEach(tooltipTriggerEl=>{new bootstrap.Tooltip(tooltipTriggerEl)})}}}